choose.when:
select c.id as item_id, #{groupid} as groupid, #{typeId} as type_id,
       c.number as item_code, c.name as item_name, 1 as status, c.opttime as created_time
from db_erp.t_erp_customer c
where c.shopid = #{shopid}
 and c.number = #{itemCode}
 and c.name like concat('%', #{itemName}, '%')

otherwise.where:
 and groupid=#{groupid}
and type_id = #{typeId}
and item_code = #{itemCode}
and item_name like concat('%', #{itemName}, '%')
and status = #{status}
and created_time = #{createTime}

mapper.update:
update fin_auxiliary_items
groupid = #{groupid}, type_id = #{typeId}, item_code = #{itemCode}, item_name = #{itemName}, status = #{status}, created_time = #{createTime},
where item_id = #{itemId}
